	('life-young-professional', 'LIFe', 'LIFe stands for Lynchburg International Fellowship. We meet weekly for worship, Bible study, and fellowship. Contact the group leader for address. Join our WhatsApp group to stay updated on our weekly meeting agenda.', '{lin-ho,tyler-levin}', '{}', false),
	('forest-young-family', 'Forest Family', 'We meet weekly for Bible study. This group provides childcare for ages 5–12.', '{qing-liu}', '{}', false),
