INSERT INTO "public"."notes" ("id", "person_id", "family_id", "type", "visibility", "contact_method", "content", "mentions", "created_by", "created_at", "todo_id") VALUES
	('note-1', 'xiang-you', NULL, 'check-in', 'private', NULL, 'Caught up with Bob after Sunday service. He seems to be settling in well — started attending the students group regularly. Mentioned he''s been feeling some pressure with grad school deadlines. Encouraged him to stay connected.', '{}', 'shepherd-1', '2026-04-01 13:15:41.860231+00', NULL),
	('note-2', 'daini-eades', NULL, 'prayer-request', 'private', NULL, 'Daini reached out over WeChat. She and Jacob are navigating a difficult season — Jacob is between jobs and they''re feeling the financial strain. Asked for prayer for wisdom and provision. Will follow up in person next week.', '{}', 'shepherd-1', '2026-03-28 13:15:41.860231+00', NULL),
	('note-3', 'fangyu-ai', NULL, 'check-in', 'private', NULL, 'Brief check-in with Fangyu on WeChat. She''s been adjusting well to the new city. Mentioned she misses her family back home but finds the young family group really welcoming. Encouraged her to keep coming.', '{}', 'shepherd-1', '2026-03-21 13:15:41.860231+00', NULL),
	('note-4', 'ryan-sparklin', NULL, 'general', 'private', NULL, 'Called Ryan to check in. He and Miranda just had their second child — everyone is healthy! They''re a bit overwhelmed with the newborn and a toddler but in good spirits. Offered to organize a meal train through the group.', '{}', 'shepherd-1', '2026-03-29 13:15:41.860231+00', NULL),
	('note-6', 'anne-park-braswell', NULL, 'check-in', 'private', NULL, 'Texted Anne to see how she''s doing. She''s been busy with work and the kids'' schedules but appreciated the message. Said she and Daniel are planning to attend the Young Family Group retreat.', '{}', 'shepherd-1', '2026-03-25 13:15:41.860231+00', NULL),
	('note-7', 'zach-sun', NULL, 'event', 'public', NULL, 'Met Zach at the church picnic. First time seeing him since he started attending. He seemed quiet but engaged. Introduced him to a few others in the students group. Will make a point to connect more intentionally.', '{}', 'shepherd-1', '2026-03-14 13:15:41.860231+00', NULL),
	('note-8', NULL, 'eades-family', 'event', 'private', NULL, 'Had the Eades family over for dinner with two other young families. Great time of fellowship. The kids played together. Jacob and Daini opened up more in this setting — feeling more like they belong.', '{}', 'shepherd-1', '2026-03-17 13:15:41.860231+00', NULL),
	('note-9', 'gillian-tang', NULL, 'check-in', 'private', NULL, 'Had coffee with Gillian after Wednesday prayer meeting. She''s doing really well — very involved in the worship team. Mentioned she''s been thinking about deeper Bible study and is considering joining the discipleship track.', '{}', 'shepherd-2', '2026-04-02 13:15:41.860231+00', NULL),
	('note-10', 'moana-xia', NULL, 'prayer-request', 'private', NULL, 'Moana called, quite distressed. She''s been struggling with loneliness since moving here from the Bay Area. Her parents are also going through some health issues back home. Prayed with her on the phone. Plan to introduce her to a few more women in the group.', '{}', 'shepherd-2', '2026-03-25 13:15:41.860231+00', NULL),
	('note-11', 'lin-ho', NULL, 'prayer-request', 'private', NULL, 'Lisa messaged asking for prayer for her marriage — she and Tyler have been going through a rough patch. She seemed hesitant to share details but wanted someone to know. Encouraged her to consider speaking with Pastor Qing together. Praying for them.', '{}', 'shepherd-2', '2026-03-30 13:15:41.860231+00', NULL),
	('note-12', 'ella-zajonc', NULL, 'check-in', 'private', NULL, 'Texted Ella to check in — she missed the last two Sundays. She replied that she''d been traveling for work. Seems fine, just busy. Will follow up if she misses again.', '{}', 'shepherd-2', '2026-03-27 13:15:41.860231+00', NULL),
	('note-13', 'natalie-cummings', NULL, 'general', 'private', NULL, 'Natalie mentioned she''s interested in getting baptized. She said she''s been a believer for years but never took the step formally. Pointed her toward the membership class and will loop in Pastor Qing.', '{}', 'shepherd-2', '2026-03-20 13:15:41.860231+00', NULL),
	('note-14', 'jessica-wang', NULL, 'check-in', 'public', NULL, 'Good conversation with Jessica at the women''s event. She''s recently started a new job and loves it. Also mentioned she''s been reading through the New Testament on her own — encouraged her.', '{}', 'shepherd-2', '2026-03-05 13:15:41.860231+00', NULL),
	('note-15', 'gillian-tang', NULL, 'check-in', 'private', NULL, 'Checked in via text before the holidays. Gillian said she''s heading home to see family — asked for prayer for some family tension she anticipates. Will follow up when she returns.', '{}', 'shepherd-2', '2026-02-28 13:15:41.860231+00', NULL),
	('note-16', 'long-cheng', NULL, 'general', 'private', NULL, 'Met with Long over lunch to review how his group is doing. He''s handling things well but mentioned feeling stretched with his own life responsibilities. Encouraged him, reminded him shepherding is about relationship, not performance.', '{}', 'admin', '2026-04-03 13:15:41.860231+00', NULL),
	('note-17', 'tyler-levin', NULL, 'prayer-request', 'private', NULL, 'Tyler pulled me aside after service. He and Lisa have been having some tension at home. He mentioned feeling disconnected from the church community. Asked for prayer and for some pastoral guidance. We''ll meet for coffee next week.', '{}', 'admin', '2026-03-31 13:15:41.860231+00', NULL),
	('note-18', 'mark-miller', NULL, 'check-in', 'private', NULL, 'Called Mark. He and Vicki have been faithful attendees. He mentioned they''d love to see more seniors get connected. We discussed the idea of a 40+ social event in the spring.', '{}', 'admin', '2026-03-26 13:15:41.860231+00', NULL),
	('note-19', 'rachel-liu', NULL, 'check-in', 'private', NULL, 'Checked in with Rachel on WeChat. She''s been coming consistently since transferring from another church. Seems eager to serve but still finding her footing. Suggested she connect with the welcome team.', '{}', 'admin', '2026-03-23 13:15:41.860231+00', NULL),
	('note-20', 'eric-chen', NULL, 'event', 'public', NULL, 'Eric shared his testimony at the membership class — very moving. He credited the student group for helping him through a difficult time in his faith. The whole class was encouraged.', '{}', 'admin', '2026-03-10 13:15:41.860231+00', NULL),
	('mnyuoh9c807v8', 'angelina-chen', NULL, 'check-in', 'public', NULL, 'Collect a photo
